package com.example.news.aggregation.agent.enums;/** * 对话状态枚举 * 定义Agent与用户对话的FSM状态 */public enum ConversationState {    /**     * 需要明确范围 - 用户query不明确，需要追问     */    NEED_SCOPE,        /**     * 检索阶段 - 正在执行检索和重排序     */    RETRIEVE,    /**     * 组装阶段 - 正在生成最终答案     */    COMPOSE,    /**     * 完成 - 已返回答案，等待用户下一轮对话     */    DONE}